in domain = ${requestName}DomainFactory.newInstance(${newInstanceParams?join(\", \")});\n        domain.create();\n        return ${requestName}DomainRepository.save(domain);\n    }\n\n    public Mono<Void> update(${className}Command command) {\n        <#assign updateParams = []>\n        <#list aggregateViews as aggregateView>\n            <#if aggregateView.objectType != 1 && aggregateView.objectType != 4>\n                <#assign fieldList = aggregateView.objectValue?replace(\'\"\', \'\')?replace(\'[\', \'\')?replace(\']\', \'\')?split(\",\")>\n                <#assign constructorParams = []>\n                <#list fieldList as field>\n                    <#assign fieldTrimmed = field?trim>\n                    <#list columnsViews as col>\n                        <#if col.propJavaEntity == fieldTrimmed>\n                            <#assign constructorParams += [\"command.get\" + fieldTrimmed?cap_first + \"()\"]>\n                        </#if>\n                    </#list>\n                </#list>\n                <#assign varName = aggregateView.objectName?uncap_first>\n        ${aggregateView.objectName} ${varName} = new ${aggregateView.objectName}(${constructorParams?join(\", \")});\n                <#assign updateParams += [varName]>\n            </#if>\n        </#list>\n\n        <#list aggregateViews as aggregateView>\n            <#if aggregateView.objectType == 1>\n        return ${requestName}DomainRepository.load(new ${aggregateView.objectName}(command.getId()))\n                .flatMap(domain -> {\n                    domain.update(${updateParams?join(\", \")});\n                    return ${requestName}DomainRepository.save(domain);\n                }).then();\n            </#if>\n        </#list>\n    }\n\n    public Mono<Void> delete(List<Long> ids) {\n        return delete${className}DomainService.deleteByIds(ids);\n    }\n    \n    public Mono<Void> restore(List<Long> ids) {\n        return restore${className}DomainService.restoreByIds(ids);\n    }\n\n    public Mono<Void> wipe(List<Long> ids) {\n        return wipe${className}DomainService.wipeByIds(ids);\n    }\n}\n','zhangsan','zhangsan',NULL,NULL,0,11);
INSERT INTO `gen_template` VALUES (1756991081276000,'restoreDomain','package ${packageName}.domain.${moduleName};\n\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\npublic interface Restore${className}DomainService {\n\n    Mono<Void> restoreByIds(List<Long> ids);\n\n}\n','zhangsan','zhangsan',NULL,NULL,0,2);
INSERT INTO `gen_template` VALUES (1756991153492000,'restoreDomainImpl','package ${packageName}.application.service.${moduleName};\n\nimport ${packageName}.domain.auth.ReactiveSecurityUtils;\nimport ${packageName}.domain.${moduleName}.*;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.stereotype.Component;\nimport reactor.core.publisher.Flux;\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\n@Component\n@RequiredArgsConstructor\npublic class Restore${className}DomainServiceImpl implements Restore${className}DomainService {\n\n    private final ${className}DomainRepository domainRepository;\n    <#assign idParams = []>\n    <#list aggregateViews as aggregateView>\n        <#if aggregateView.objectType == 1>\n            <#assign idParams += [aggregateView.objectName]>\n        </#if>\n    </#list>\n    \n    @Override\n    public Mono<Void> restoreByIds(List<Long> ids) {\n        return Flux.fromIterable(ids)\n                .flatMap(id -> domainRepository.load(new ${idParams?join(\", \")}(id))\n                        .flatMap(domain -> {\n                            domain.restore();\n                            return domainRepository.save(domain);\n                        }), ReactiveSecurityUtils.concurrency())\n                .then();\n    }\n}\n','zhangsan','zhangsan',NULL,NULL,0,4);
INSERT INTO `gen_template` VALUES (1757042433848000,'queryService','package ${packageName}.application.service.${moduleName};\n\nimport ${packageName}.application.service.${moduleName}.dto.*;\nimport ${packageName}.domain.util.PageResponse;\nimport ${packageName}.infrastructure.persistence.entity.${className}Entity;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.data.r2dbc.core.R2dbcEntityTemplate;\nimport org.springframework.data.relational.core.query.Criteria;\nimport org.springframework.data.relational.core.query.Query;\nimport org.springframework.stereotype.Service;\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\n@Service\n@RequiredArgsConstructor\npublic class ${className}QueryService {\n\n    private final R2dbcEntityTemplate r2dbcEntityTemplate;\n\n    private final ${className}ViewMapStruct mapStruct;\n\n    public Mono<PageResponse<${className}View>> index(${className}PageQuery query) {\n<#assign criteriaGenerated = false>\n<#list columnsViews as columnsView>\n    <#assign fields = [\"deleteStatus\"]>\n    <#list fields as field>\n        <#if columnsView.propJavaEntity == field && !criteriaGenerated>\n        Criteria criteria = Criteria.where(${className}Query.Fields.deleteStatus).is(false);\n            <#assign criteriaGenerated = true>\n        </#if>\n    </#list>\n</#list>\n<#if !criteriaGenerated>\n        Criteria criteria = Criteria.empty();\n</#if>\n        Query qry = Query.query(criteria)\n                .limit(query.getPageSize())\n                .offset((long) (query.getPageNum() - 1) * query.getPageSize());\n        Mono<List<${className}View>> list = r2dbcEntityTemplate.select(${className}Entity.class).matching(qry).all().collectList().map(mapStruct::toViews);\n        Mono<Long> count = r2dbcEntityTemplate.count(Query.query(criteria), ${className}Entity.class);\n        return Mono.zip(list, count).map(tuple -> new PageResponse<>(tuple.getT1(), tuple.getT2(), query.getPageNum(), query.getPageSize()));\n    }\n\n    public Mono<PageResponse<${className}View>> recycle(${className}PageQuery query) {\n<#assign criteriaGenerated = false>\n<#list columnsViews as columnsView>\n    <#assign fields = [\"deleteStatus\"]>\n    <#list fields as field>\n        <#if columnsView.propJavaEntity == field && !criteriaGenerated>\n        Criteria criteria = Criteria.where(${className}Query.Fields.deleteStatus).is(true);\n            <#assign criteriaGenerated = true>\n        </#if>\n    </#list>\n</#list>\n<#if !criteriaGenerated>\n        Criteria criteria = Criteria.empty();\n</#if>\n        Query qry = Query.query(criteria)\n                .limit(query.getPageSize())\n                .offset((long) (query.getPageNum() - 1) * query.getPageSize());\n        Mono<List<${className}View>> list = r2dbcEntityTemplate.select(${className}Entity.class).matching(qry).all().collectList().map(mapStruct::toViews);\n        Mono<Long> count = r2dbcEntityTemplate.count(Query.query(criteria), ${className}Entity.class);\n        return Mono.zip(list, count).map(tuple -> new PageResponse<>(tuple.getT1(), tuple.getT2(), query.getPageNum(), query.getPageSize()));\n    }\n}\n','zhangsan','zhangsan',NULL,NULL,0,7);
INSERT INTO `gen_template` VALUES (1757042705558000,'controller','package ${packageName}.web;\n\nimport ${packageName}.application.service.${moduleName}.${className}CommandService;\nimport ${packageName}.application.service.${moduleName}.${className}QueryService;\nimport ${packageName}.application.service.${moduleName}.dto.${className}Command;\nimport ${packageName}.application.service.${moduleName}.dto.${className}PageQuery;\nimport ${packageName}.domain.util.ApiResponse;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.validation.annotation.Validated;\nimport org.springframework.web.bind.annotation.*;\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\n@RestController\n@RequiredArgsConstructor\n@RequestMapping(\"/${moduleName}/${requestName}\")\npublic class ${className}Controller {\n\n    private final ${className}QueryService queryService;\n\n    private final ${className}CommandService commandService;\n\n    @PostMapping(\"/index\")\n    public Mono<ApiResponse> index(@RequestBody @Validated Mono<${className}PageQuery> query) {\n        return ApiResponse.validated(query, queryService::index);\n    }\n\n    @PostMapping(\"/recycle\")\n    public Mono<ApiResponse> recycle(@RequestBody @Validated Mono<${className}PageQuery> query) {\n        return ApiResponse.validated(query, queryService::recycle);\n    }\n\n    @PostMapping(\"/create\")\n    public Mono<ApiResponse> create(@RequestBody ${className}Command command) {\n        return ApiResponse.ok(commandService.create(command));\n    }\n\n    @PutMapping(\"/update\")\n    public Mono<ApiResponse> update(@RequestBody ${className}Command command) {\n        return ApiResponse.ok(commandService.update(command));\n    }\n\n    @PostMapping(\"/delete\")\n    public Mono<ApiResponse> delete(@RequestParam(\"ids\") List<Long> ids) {\n        return ApiResponse.ok(commandService.delete(ids));\n    }\n\n    @PostMapping(\"/restore\")\n    public Mono<ApiResponse> restore(@RequestParam(\"ids\") List<Long> ids) {\n        return ApiResponse.ok(commandService.restore(ids));\n    }\n\n    @DeleteMapping(\"/wipe\")\n    public Mono<ApiResponse> wipe(@RequestParam(\"ids\") List<Long> ids) {\n        return ApiResponse.ok(commandService.wipe(ids));\n    }\n}\n','zhangsan','zhangsan',NULL,NULL,0,4);
INSERT INTO `gen_template` VALUES (1757273731338000,'index.vue','<script lang=\"ts\" setup>\nimport type { VbenFormProps } from \'#/adapter/form\';\nimport type { VxeTableGridOptions } from \'#/adapter/vxe-table\';\n\nimport { ref } from \'vue\';\n\nimport { useAccess } from \'@vben/access\';\nimport { confirm, Page } from \'@vben/common-ui\';\nimport { $t } from \'@vben/locales\';\n\nimport { ElButton, ElMessage } from \'element-plus\';\n<#assign filteredProperties = columnsViews?filter(p -> p.propDictId?exists && p.propDictId?has_content)>\n<#if filteredProperties?has_content>\nimport Dict from \'#/adapter/component/Dict.vue\';\n</#if>\n\nimport { useVbenVxeGrid } from \'#/adapter/vxe-table\';\nimport { delete${className}, get${className}Page } from \'#/api/${moduleName}/${requestName}\';\n\nimport ${className}Form from \'./form.vue\';\nimport RecycleForm from \'./recycle.vue\';\n\nconst { hasAccessByCodes } = useAccess();\n\nconst ${requestName}FormRef = ref();\nconst recycleFormRef = ref();\n\ninterface RowType {\n<#assign excludeFields = [\"createBy\", \"createTime\", \"updateBy\", \"updateTime\", \"version\", \"deleteStatus\"]>\n<#list columnsViews as property>\n    <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n  ${property.propJavaEntity}: ${property.typescriptTypeStr};\n    </#if>\n</#list>\n}\n<#assign filteredProperties = columnsViews?filter(p -> p.tableFilter)>\n<#if filteredProperties?has_content>\nconst formOptions: VbenFormProps = {\n    collapsed: false,\n    schema: [\n        <#list filteredProperties as property>\n        {\n            component: \"${property.tableFilterComponentStr}\",\n            componentProps: {\n                placeholder: `<#noparse>${$t(\'system.common.placeholder.input\')} ${$t(\'</#noparse>${requestName}.${property.propJavaEntity}<#noparse>\')}</#noparse>`,\n            },\n            fieldName: \'${property.propJavaEntity}\',\n            label: $t(\'${requestName}.${property.propJavaEntity}\'),\n        }<#if property_has_next>,</#if>\n        </#list>\n    ],\n    showCollapseButton: true,\n    submitButtonOptions: {\n        content: \"$t(\'system.common.button.search\')\",\n    },\n    resetButtonOptions: {\n        content: \"$t(\'system.common.button.reset\')\",\n    },\n    submitOnChange: false,\n    submitOnEnter: true,\n};\n</#if>\nconst gridOptions: VxeTableGridOptions<RowType> = {\n  checkboxConfig: {\n    highlight: true,\n  },\n  columnConfig: {\n    resizable: true,\n  },\n  rowConfig: {\n    isHover: true,\n  },\n  columns: [\n    { title: \'No.\', type: \'seq\', width: 50 },\n    { align: \'left\', title: \'#\', type: \'checkbox\', width: 50 },\n<#assign excludeFields = [\"id\", \"createBy\", \"createTime\", \"updateBy\", \"updateTime\", \"version\", \"deleteStatus\"]>\n<#list columnsViews as property>\n    <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n    <#if property?has_content && property.propDictId?has_content>\n    {\n      field: \'${property.propJavaEntity}\',\n      title: $t(\'${requestName}.${property.propJavaEntity}\'),\n      slots: { default: \'${property.propJavaEntity}\' },\n    },\n    <#else>\n    { field: \'${property.propJavaEntity}\', title: $t(\'${requestName}.${property.propJavaEntity}\') },\n    </#if>\n    </#if>\n</#list>\n    {\n      field: \'action\',\n      fixed: \'right\',\n      slots: { default: \'action\' },\n      title: <#noparse>$t(\'system.common.operation\')</#noparse>,\n      width: 150,\n    },\n  ],\n  exportConfig: {},\n  keepSource: true,\n  proxyConfig: {\n    ajax: {\n<#assign filteredProperties = columnsViews?filter(p -> p.tableFilter)>\n<#if filteredProperties?has_content>\n      query: async ({ page }, formOptions) => {\n        return await get${className}Page({\n          pageNum: page.currentPage,\n          pageSize: page.pageSize,\n          ...formOptions,\n        });\n      },\n<#else>\n      query: async ({ page }) => {\n        return await get${className}Page({\n          pageNum: page.currentPage,\n          pageSize: page.pageSize,\n        });\n      },\n</#if>\n    },\n  },\n  editConfig: {\n    mode: \'row\',\n    trigger: \'click\',\n  },\n  toolbarConfig: {\n    custom: true,\n    export: true,\n    // import: true,\n    refresh: true,\n    zoom: true,\n<#assign filteredProperties = columnsViews?filter(p -> p.tableFilter)>\n<#if filteredProperties?has_content>\n    search: true,\n<#else>\n    search: false,\n</#if>\n  },\n};\n\nconst [Grid, gridApi] = useVbenVxeGrid({\n  gridOptions,\n<#assign filteredProperties = columnsViews?filter(p -> p.tableFilter)>\n<#if filteredProperties?has_content>\n  formOptions,\n</#if>\n});\n\nconst openRecycleForm = () => {\n  recycleFormRef.value?.open();\n};\n\nconst openForm = () => {\n  ${requestName}FormRef.value?.open();\n};\n\nconst editRow = (row: RowType) => {\n  ${requestName}FormRef.value?.open(row);\n};\n\nconst deleteMethod = (row?: RowType) => {\n  const ids: string[] = row\n    ? [row.id]\n    : gridApi.grid.getCheckboxRecords().map((item) => item.id);\n\n  if (ids.length === 0) {\n    ElMessage.warning(<#noparse>$t(\'system.common.delete.warning\')</#noparse>);\n    return;\n  }\n\n  confirm({\n    content: <#noparse>$t(\'system.common.delete.confirm\')</#noparse>,\n    icon: \'error\',\n  }).then(async () => {\n    try {\n      await delete${className}(ids);\n      await gridApi.reload();\n      ElMessage.success(<#noparse>$t(\'system.common.delete.success\')</#noparse>);\n    } catch {\n      ElMessage.error(<#noparse>$t(\'system.common.delete.error\')</#noparse>);\n    }\n  });\n};\n</script>\n\n<template>\n  <Page>\n    <Grid>\n<#assign filteredProperties = columnsViews?filter(p -> p.propDictId?exists && p.propDictId?has_content)>\n<#if filteredProperties?has_content>\n<#list columnsViews as property>\n<#if property?has_content && property.propDictId?has_content>\n      <template #${property.propJavaEntity}=\"{ row }\">\n        <Dict dict-key=\"${property.propDictStr}\" :value=\"row.${property.propJavaEntity}\" />\n      </template>\n</#if>\n</#list>\n</#if>\n      <template #toolbar-actions>\n        <ElButton\n          class=\"mr-2\"\n          bg\n          text\n          type=\"primary\"\n          @click=\"openForm\"\n          v-if=\"hasAccessByCodes([\'${moduleName}:${requestName}:create\'])\"\n        >\n          {{ <#noparse>$t(\'system.common.button.add\')</#noparse> }}\n        </ElButton>\n        <ElButton\n          class=\"mr-2\"\n          bg\n          text\n          type=\"danger\"\n          @click=\"deleteMethod()\"\n          v-if=\"hasAccessByCodes([\'${moduleName}:${requestName}:delete\'])\"\n        >\n          {{ <#noparse>$t(\'system.common.button.delete\')</#noparse> }}\n        </ElButton>\n        <ElButton\n          class=\"mr-2\"\n          bg\n          text\n          type=\"info\"\n          @click=\"openRecycleForm\"\n          v-if=\"hasAccessByCodes([\'${moduleName}:${requestName}:recycle\'])\"\n        >\n          {{ <#noparse>$t(\'system.common.button.recycle\')</#noparse> }}\n        </ElButton>\n      </template>\n      <template #action=\"{ row }\">\n        <ElButton\n          type=\"primary\"\n          link\n          @click=\"editRow(row)\"\n          v-if=\"hasAccessByCodes([\'${moduleName}:${requestName}:update\'])\"\n        >\n          {{ <#noparse>$t(\'system.common.button.edit\')</#noparse> }}\n        </ElButton>\n        <ElButton\n          type=\"danger\"\n          link\n          @click=\"deleteMethod(row)\"\n          v-if=\"hasAccessByCodes([\'${moduleName}:${requestName}:delete\'])\"\n        >\n          {{ <#noparse>$t(\'system.common.button.delete\')</#noparse> }}\n        </ElButton>\n      </template>\n    </Grid>\n    <${className}Form ref=\"${requestName}FormRef\" :grid-api=\"gridApi\" />\n    <RecycleForm ref=\"recycleFormRef\" :grid-api=\"gridApi\" />\n  </Page>\n</template>\n','zhangsan','zhangsan',NULL,'2026-06-16 15:09:34',0,50);
INSERT INTO `gen_template` VALUES (1757596954435000,'i18n.en.json','{\n  \"title\": \"${className} Management\",\n  <#assign excludeFields = [\"createBy\", \"createTime\", \"updateBy\", \"updateTime\", \"version\", \"deleteStatus\"]>\n  <#assign includedProps = []>\n  <#list columnsViews as property>\n    <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n      <#assign includedProps += [property]>\n    </#if>\n  </#list>\n  <#list includedProps as prop>\n  \"${prop.propJavaEntity}\": \"${prop.en}\"<#if prop_has_next>,</#if>\n  </#list>\n}','zhangsan','zhangsan',NULL,NULL,0,3);
INSERT INTO `gen_template` VALUES (1757837002412000,'i18n.locale.json','<#assign allLocaleNotEmpty = true>\n<#list columnsViews as item>\n  <#if !(item.locale?has_content)>\n    <#assign allLocaleNotEmpty = false>\n    <#break>\n  </#if>\n</#list>\n<#if allLocaleNotEmpty>\n{\n  \"title\": \"${className} Management\",\n  <#assign excludeFields = [\"createBy\", \"createTime\", \"updateBy\", \"updateTime\", \"version\", \"deleteStatus\"]>\n  <#assign includedProps = []>\n  <#list columnsViews as property>\n    <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n      <#assign includedProps += [property]>\n    </#if>\n  </#list>\n  <#list includedProps as prop>\n  \"${prop.propJavaEntity}\": \"${prop.locale}\"<#if prop_has_next>,</#if>\n  </#list>\n}\n</#if>\n','zhangsan','zhangsan',NULL,NULL,0,2);
INSERT INTO `gen_template` VALUES (1757927072241000,'recycle.vue','<script lang=\"ts\" setup>\nimport type { VxeTableGridOptions } from \'#/adapter/vxe-table\';\n\nimport { useAccess } from \'@vben/access\';\nimport { confirm, Page } from \'@vben/common-ui\';\nimport { $t } from \'@vben/locales\';\n\nimport { ElButton, ElMessage } from \'element-plus\';\n<#assign filteredProperties = columnsViews?filter(p -> p.propDictId?exists && p.propDictId?has_content)>\n<#if filteredProperties?has_content>\nimport Dict from \'#/adapter/component/Dict.vue\';\n</#if>\n\nimport { useVbenVxeGrid } from \'#/adapter/vxe-table\';\nimport {\n  get${className}RecyclePage,\n  restore${className},\n  wipe${className}\n} from \'#/api/${moduleName}/${requestName}\';\n\nconst props = defineProps<{\n  gridApi: any;\n}>();\n\nconst { hasAccessByCodes } = useAccess();\n\ninterface RowType {\n<#assign excludeFields = [\"createBy\", \"createTime\", \"updateBy\", \"updateTime\", \"version\", \"deleteStatus\"]>\n<#list columnsViews as property>\n    <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n  ${property.propJavaEntity}: ${property.typescriptTypeStr};\n    </#if>\n</#list>\n}\n\nconst gridOptions: VxeTableGridOptions<RowType> = {\n  checkboxConfig: {\n    highlight: true,\n  },\n  columnConfig: {\n    resizable: true,\n  },\n  rowConfig: {\n    isHover: true,\n  },\n  columns: [\n    { title: \'No.\', type: \'seq\', width: 50 },\n    { align: \'left\', title: \'#\', type: \'checkbox\', width: 50 },\n<#assign excludeFields = [\"id\", \"createBy\", \"createTime\", \"updateBy\", \"updateTime\", \"version\", \"deleteStatus\"]>\n<#list columnsViews as property>\n    <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n    <#if property?has_content && property.propDictId?has_content>\n    {\n      field: \'${property.propJavaEntity}\',\n      title: $t(\'${requestName}.${property.propJavaEntity}\'),\n      slots: { default: \'${property.propJavaEntity}\' },\n    },\n    <#else>\n    { field: \'${property.propJavaEntity}\', title: $t(\'${requestName}.${property.propJavaEntity}\') },\n    </#if>\n    </#if>\n</#list>\n    {\n      field: \'action\',\n      fixed: \'right\',\n      slots: { default: \'action\' },\n      title: $t(\'system.common.operation\'),\n      width: 150,\n    },\n  ],\n  exportConfig: {},\n  keepSource: true,\n  proxyConfig: {\n    ajax: {\n      query: async ({ page }) => {\n        return await get${className}RecyclePage({\n          pageNum: page.currentPage,\n          pageSize: page.pageSize,\n        });\n      },\n    },\n  },\n  editConfig: {\n    mode: \'row\',\n    trigger: \'click\',\n  },\n  toolbarConfig: {\n    custom: true,\n    export: true,\n    // import: true,\n    refresh: true,\n    zoom: true,\n    search: false,\n  },\n};\n\nconst [Grid, localGridApi] = useVbenVxeGrid({\n  gridOptions,\n});\n\nconst wipeMethod = (row?: RowType) => {\n  const ids: string[] = row\n    ? [row.id]\n    : localGridApi.grid.getCheckboxRecords().map((item) => item.id);\n\n  if (ids.length === 0) {\n    ElMessage.warning($t(\'system.common.delete.warning\'));\n    return;\n  }\n\n  confirm({\n    content: $t(\'system.common.delete.confirm\'),\n    icon: \'error\',\n  }).then(async () => {\n    await wipe${className}(ids)\n      .then(async () => {\n        await localGridApi.reload();\n        ElMessage.success($t(\'system.common.delete.success\'));\n        await props.gridApi.reload();\n      })\n      .catch(() => {\n        ElMessage.error($t(\'system.common.delete.error\'));\n      });\n  });\n};\n\nconst restoreMethod = (row?: RowType) => {\n  const ids: string[] = row\n    ? [row.id]\n    : localGridApi.grid.getCheckboxRecords().map((item) => item.id);\n\n  if (ids.length === 0) {\n    ElMessage.warning($t(\'system.common.restore.warning\'));\n    return;\n  }\n\n  confirm({\n    content: $t(\'system.common.restore.confirm\'),\n    icon: \'error\',\n  }).then(async () => {\n    try {\n      await restore${className}(ids);\n      await localGridApi.reload();\n      await props.gridApi.reload();\n      ElMessage.success($t(\'system.common.restore.success\'));\n    } catch {\n      ElMessage.error($t(\'system.common.restore.error\'));\n    }\n  });\n};\n</script>\n\n<template>\n  <Page>\n    <Grid>\n<#assign filteredProperties = columnsViews?filter(p -> p.propDictId?exists && p.propDictId?has_content)>\n<#if filteredProperties?has_content>\n<#list columnsViews as property>\n<#if property?has_content && property.propDictId?has_content>\n      <template #${property.propJavaEntity}=\"{ row }\">\n        <Dict dict-key=\"${property.propDictStr}\" :value=\"row.${property.propJavaEntity}\" />\n      </template>\n</#if>\n</#list>\n</#if>\n      <template #toolbar-actions>\n        <ElButton\n          class=\"mr-2\"\n          bg\n          text\n          type=\"primary\"\n          @click=\"restoreMethod()\"\n          v-if=\"hasAccessByCodes([\'${moduleName}:${requestName}:restore\'])\"\n        >\n          {{ <#noparse>$t(\'system.common.button.restore\')</#noparse> }}\n        </ElButton>\n        <ElButton\n          class=\"mr-2\"\n          bg\n          text\n          type=\"danger\"\n          @click=\"wipeMethod()\"\n          v-if=\"hasAccessByCodes([\'${moduleName}:${requestName}:wipe\'])\"\n        >\n          {{ <#noparse>$t(\'system.common.button.delete\')</#noparse> }}\n        </ElButton>\n      </template>\n      <template #action=\"{ row }\">\n        <ElButton\n          type=\"success\"\n          link\n          @click=\"restoreMethod(row)\"\n          v-if=\"hasAccessByCodes([\'${moduleName}:${requestName}:restore\'])\"\n        >\n          {{ <#noparse>$t(\'system.common.button.restore\')</#noparse> }}\n        </ElButton>\n        <ElButton\n          type=\"danger\"\n          link\n          @click=\"wipeMethod(row)\"\n          v-if=\"hasAccessByCodes([\'${moduleName}:${requestName}:wipe\'])\"\n        >\n          {{ <#noparse>$t(\'system.common.button.wipe\')</#noparse> }}\n        </ElButton>\n      </template>\n    </Grid>\n  </Page>\n</template>\n','zhangsan','zhangsan',NULL,NULL,0,7);
INSERT INTO `gen_template` VALUES (1758011415645000,'form.vue','<script lang=\"ts\" setup>\nimport { ref } from \'vue\';\n\nimport { useVbenModal } from \'@vben/common-ui\';\nimport { $t } from \'@vben/locales\';\n\nimport { ElMessage } from \'element-plus\';\n\nimport { useVbenForm } from \'#/adapter/form\';\nimport { create${className}, update${className} } from \'#/api/${moduleName}/${requestName}\';\n<#assign filteredProperties = columnsViews?filter(p -> p.propDictId?exists && p.propDictId?has_content)>\n<#if filteredProperties?has_content>\nimport { getItemLabelByDictCode } from \'#/api/sys/dict/\';\n</#if>\n\nconst props = defineProps<{\n  gridApi: any;\n}>();\n\nconst writeForm = ref<Record<string, any>>({});\n\nconst [Form, formApi] = useVbenForm({\n  showDefaultActions: false,\n  layout: \'horizontal\',\n  commonConfig: {\n    componentProps: {\n      class: \'w-full\',\n    },\n    colon: true,\n    labelWidth: 150,\n  },\n  submitOnChange: true,\n  schema: [\n<#assign excludeFields = [\"id\", \"createBy\", \"createTime\", \"updateBy\", \"updateTime\", \"version\", \"deleteStatus\"]>\n<#list columnsViews as property>\n<#if !excludeFields?seq_contains(property.propJavaEntity)>\n<#if !property.propDictId?exists && !property.propDictId?has_content>\n    {\n      component: \'${property.formComponentStr}\',\n      fieldName: \'${property.propJavaEntity}\',\n      label: $t(\'${requestName}.${property.propJavaEntity}\'),\n      componentProps: {\n        placeholder: `<#noparse>${$t(\'system.common.placeholder.input\')} ${$t(\'</#noparse>${requestName}.${property.propJavaEntity}<#noparse>\')}</#noparse>`,\n      },\n      rules: \'required\',\n    },\n<#else>\n    {\n      component: \'${property.formComponentStr}\',\n      componentProps: {\n        allowClear: true,\n        filterOption: true,\n        api: getComponentDict,\n        showSearch: true,\n        labelField: \'itemLabel\',\n        valueField: \'itemValue\',\n        clearable: true,\n        placeholder: `<#noparse>${$t(\'system.common.placeholder.input\')} ${$t(\'</#noparse>${requestName}.${property.propJavaEntity}<#noparse>\')}</#noparse>`,\n      },\n      fieldName: \'${property.propJavaEntity}\',\n      label: $t(\'${requestName}.${property.propJavaEntity}\'),\n      rules: \'required\',\n    },\n</#if>\n</#if>\n</#list>\n  ],\n});\n\nconst [Modal, modalApi] = useVbenModal({\n  onConfirm: () => {\n    formApi.validate().then(async (e) => {\n      if (e.valid) {\n        Object.assign(writeForm.value, await formApi.getValues());\n        await (writeForm.value.id\n          ? update${className}(writeForm.value)\n          : create${className}(writeForm.value));\n        ElMessage.success($t(\'system.common.save.success\'));\n        props.gridApi.reload();\n      } else {\n        ElMessage.error($t(\'system.common.validation.error\'));\n      }\n      await modalApi.setState({ loading: false }).close();\n    });\n  },\n  confirmText: $t(\'system.common.button.confirm\'),\n  cancelText: $t(\'system.common.button.cancel\'),\n});\n\nconst open = (row: any) => {\n  writeForm.value = {};\n  if (row?.id) {\n    writeForm.value = row;\n    formApi.setValues(row);\n  } else {\n    formApi.resetForm();\n  }\n  modalApi.open();\n};\nconst close = () => modalApi.close();\n\ndefineExpose({ open, close });\n<#if filteredProperties?has_content>\nfunction getComponentDict() {\n  return getItemLabelByDictCode(\'components\');\n}\n</#if>\n</script>\n\n<template>\n  <Modal class=\"w-[40%]\" :title=\"$t(\'system.common.alert.form\')\">\n    <Form style=\"width: auto\" />\n  </Modal>\n</template>\n','zhangsan','zhangsan',NULL,NULL,0,4);
INSERT INTO `gen_template` VALUES (1758012509016000,'api.ts','import { requestClient } from \'#/api/request\';\n\nexport async function get${className}Page(data: any) {\n  return requestClient.post(\'/${moduleName}/${requestName}/index\', data);\n}\n\nexport async function get${className}RecyclePage(data: any) {\n  return requestClient.post(\'/${moduleName}/${requestName}/recycle\', data);\n}\n\nexport async function create${className}(data: any) {\n  return requestClient.post(\'/${moduleName}/${requestName}/create\', data);\n}\n\nexport async function update${className}(data: any) {\n  return requestClient.put(\'/${moduleName}/${requestName}/update\', data);\n}\n\nexport async function delete${className}(data: any) {\n  return requestClient.post(\'/${moduleName}/${requestName}/delete\', null, {\n    params: {\n      ids: data,\n    },\n  });\n}\n\nexport async function restore${className}(data: any) {\n  return requestClient.post(\'/${moduleName}/${requestName}/restore\', null, {\n    params: {\n      ids: data,\n    },\n  });\n}\n\nexport async function wipe${className}(data: any) {\n  return requestClient.delete(\'/${moduleName}/${requestName}/wipe\', {\n    params: {\n      ids: data,\n    },\n  });\n}\n','zhangsan','zhangsan',NULL,NULL,0,2);
INSERT INTO `gen_template` VALUES (1759827759624000,'readme.txt','============ CN ================\n\n1. 将 README 目录下的 SQL.sql 放入到你的数据库中执行。\n\n2. 将如下 ts 追加到 apps/web-ele/src/api/${moduleName} 目录下（如果该目录下没有 index.ts 则手动创建一个，再追加进去）:\nexport * from \'./${requestName}/\';\n\n3. 将如下 ts 追加到 apps/web-ele/src/api/index.ts（只需要追加菜单目录名）:\nexport * from \'./${moduleName}\';\n\n============ EN ================\n\n1. Drop the `SQL.sql` from the README folder into your database and run it.\n\n2. Add this TS snippet to `apps/web‑ele/src/api/${moduleName}` – if there’s no `index.ts` in that folder, create one first and then append:  \n   export * from \'./${requestName}/\';\n\n3. Append the following line to `apps/web‑ele/src/api/index.ts` (just the menu‑folder name):  \n   export * from \'./${moduleName}\';','zhangsan','zhangsan',NULL,NULL,0,0);
INSERT INTO `gen_template` VALUES (1759827911084000,'sql','-- 自动生成的菜单权限 SQL\n-- module: ${moduleName}, requestName: ${requestName}\n\n-- 1. 确保 module 目录存在（默认挂在 Code Generation 下）\nINSERT IGNORE INTO `sys_menu` (\n  `id`, `parent_id`, `name`, `path`, `component`, `api`, `permission`,\n  `sort_order`, `title`, `icon`, `menu_type`,\n  `visible`, `menu_status`, `create_by`, `update_by`,\n  `create_time`, `update_time`, `delete_status`, `version`\n) VALUES (\n  ${dirId?c}, 1753246611049000, \'${moduleName?cap_first}\', \'/${moduleName}\', NULL, NULL, NULL,\n  1, \'${moduleName}.title\', \'ant-design:folder-outlined\', 1,\n  1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0\n);\n\nSET @dir_id = ${dirId?c};\n\n-- 2. 列表页菜单\nSET @menu_id = ${menuId?c};\nINSERT INTO `sys_menu` (\n  `id`, `parent_id`, `name`, `path`, `component`, `api`, `permission`,\n  `sort_order`, `title`, `menu_type`,\n  `visible`, `menu_status`, `create_by`, `update_by`,\n  `create_time`, `update_time`, `delete_status`, `version`\n) VALUES (\n  ${menuId?c}, ${dirId?c}, \'${requestName?cap_first} Management\', \'/${moduleName}/${requestName}\', \'/${moduleName}/${requestName}/index\', NULL, NULL,\n  1, \'${requestName}.title\', 2,\n  1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0\n);\n\n-- 3. 按钮权限\nINSERT INTO `sys_menu` (\n  `id`, `parent_id`, `name`, `component`, `api`, `permission`,\n  `sort_order`, `menu_type`, `visible`, `menu_status`,\n  `create_by`, `update_by`, `create_time`, `update_time`, `delete_status`, `version`\n) VALUES\n(${btnIndexId?c},   ${menuId?c}, \'Index\',   NULL, \'/${moduleName}/${requestName}/index\',   \'${moduleName}:${requestName}:index\',   1, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0),\n(${btnRecycleId?c}, ${menuId?c}, \'Recycle\', NULL, \'/${moduleName}/${requestName}/recycle\', \'${moduleName}:${requestName}:recycle\', 2, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0),\n(${btnCreateId?c},  ${menuId?c}, \'Create\',  NULL, \'/${moduleName}/${requestName}/create\',  \'${moduleName}:${requestName}:create\',  3, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0),\n(${btnUpdateId?c},  ${menuId?c}, \'Update\',  NULL, \'/${moduleName}/${requestName}/update\',  \'${moduleName}:${requestName}:update\',  4, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0),\n(${btnDeleteId?c},  ${menuId?c}, \'Delete\',  NULL, \'/${moduleName}/${requestName}/delete\',  \'${moduleName}:${requestName}:delete\',  5, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0),\n(${btnRestoreId?c}, ${menuId?c}, \'Restore\', NULL, \'/${moduleName}/${requestName}/restore\', \'${moduleName}:${requestName}:restore\', 6, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0),\n(${btnWipeId?c},    ${menuId?c}, \'Wipe\',    NULL, \'/${moduleName}/${requestName}/wipe\',    \'${moduleName}:${requestName}:wipe\',    7, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0);\n\n-- 4. 绑定到 ADMIN 角色\nINSERT INTO `sys_role_menu` (`id`, `role_id`, `menu_id`, `create_by`, `update_by`, `create_time`, `update_time`, `delete_status`) VALUES\n(${rmDirId?c},        1750159408244, ${dirId?c},        \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmMenuId?c},       1750159408244, ${menuId?c},       \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnIndexId?c},   1750159408244, ${btnIndexId?c},   \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnRecycleId?c}, 1750159408244, ${btnRecycleId?c}, \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnCreateId?c},  1750159408244, ${btnCreateId?c},  \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnUpdateId?c},  1750159408244, ${btnUpdateId?c},  \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnDeleteId?c},  1750159408244, ${btnDeleteId?c},  \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnRestoreId?c}, 1750159408244, ${btnRestoreId?c}, \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnWipeId?c},    1750159408244, ${btnWipeId?c},    \'admin\', \'admin\', NOW(), NOW(), 0);','zhangsan','zhangsan',NULL,'2026-06-19 13:53:45',0,1);
